import React from "react";

function AssignmentList({ assignments, submit }) {
  return (
    <div>
      <h2>Assignments</h2>

      <ul>
        {assignments.length === 0 && (
          <p style={{textAlign:"center"}}>No assignments available.</p>
        )}

        {assignments.map(a => (
          <li key={a.id}>
            <div>
              <strong>{a.title}</strong> <br/>
              <small>{a.subject}</small> <br/>
              Due: {a.dueDate} <br/>
              Status: 
              <span 
                className={
                  a.status === "PENDING" 
                    ? "status-pending" 
                    : "status-submitted"
                }
              >
                {" "}{a.status}
              </span>
            </div>

            {a.status === "PENDING" && (
              <button onClick={() => submit(a.id)}>
                Submit
              </button>
            )}
          </li>
        ))}
      </ul>
    </div>
  );
}

export default AssignmentList;
